const body = $input.item.json.body || {};
const lead_id = body.lead_id;
const mensagens = body.mensagens || [];

if (!lead_id) throw new Error('lead_id é obrigatório');
if (mensagens.length === 0) throw new Error('Nenhuma mensagem para analisar');

const historico = mensagens.map(m =>
  `[${m.remetente === 'cliente' ? 'Cliente' : m.remetente === 'vendedor' ? 'Vendedor' : 'IA'}] ${m.mensagem}`
).join('\n');

return { json: { lead_id, historico, total_msgs: mensagens.length } };

const h = $json.historico;

return {
  json: {
    prompt: `Você é um analista comercial especializado em serralheria (portões, grades, corrimãos, coberturas metálicas, estruturas de aço).

Analise o histórico de conversa abaixo com um cliente e extraia insights comerciais objetivos.

Regras:
- Seja direto e prático.
- Se a conversa for curta (apenas saudação), sentimento deve ser "indeciso" e objecoes null.
- NUNCA invente informações que não estão na conversa.

Histórico da conversa:
${h}

Responda APENAS o JSON abaixo, sem markdown, sem codigo extra:
{
  "sentimento": "interessado | indeciso | frustrado | emergencial | negociação",
  "objecoes": ["preco", "prazo", "concorrencia", "qualidade", "transporte", "outro"] | null,
  "acao_recomendada": "qual a melhor acao comercial agora (texto curto)",
  "resumo": "2-3 frases do que foi tratado na conversa",
  "resposta_sugerida": "frase pronta para o vendedor responder via WhatsApp personalizada para este lead"
}`
  }
};

const raw = $input.item.json;
let text = raw.output || raw.text || '';
if (!text && raw.message) text = raw.message.content;
if (!text) throw new Error('Resposta vazia da IA');

text = text.replace(/```json/g, '').replace(/```/g, '').trim();

let d;
try {
  d = JSON.parse(text);
} catch (e) {
  d = { sentimento: 'indeciso', objecoes: null, acao_recomendada: 'Reanalisar conversa', resumo: 'Erro ao processar resposta da IA', resposta_sugerida: '' };
}

const usage = $input.item.json?.usage || $json?.usage || {};
const tokens_input = usage.promptTokens || usage.input_tokens || 0;
const tokens_output = usage.completionTokens || usage.output_tokens || 0;

// Gemini 2.5 Flash: ~$0.15/1M input, ~$0.60/1M output
const custo_centavos = ((tokens_input / 1000000) * 0.15 + (tokens_output / 1000000) * 0.60) * 100;

return {
  json: {
    sentimento: d.sentimento || 'indeciso',
    objecoes: d.objecoes || null,
    acao_recomendada: d.acao_recomendada || 'Aguardando resposta do cliente',
    resumo: d.resumo || 'Analise nao disponivel',
    resposta_sugerida: d.resposta_sugerida || '',
    tokens_input,
    tokens_output,
    custo_centavos: Math.round(custo_centavos * 100) / 100
  }
};
